+/**
+ * Priority-based notification router.
+ *
+ * Routes notifications to the appropriate channel based on priority:
+ * - urgent → SMS channel
+ * - normal → email channel (NotificationService)
+ * - low → webhook channel
+ *
+ * This replaces the previous broadcast approach where all channels
+ * received all events. Now each notification goes to exactly one channel
+ * determined by its priority level.
+ *
+ * Depends on:
+ * - NotificationService (email channel)
+ * - SmsChannelService (SMS channel)
+ * - WebhookChannelService (webhook channel)
+ */
+
+import type { NotificationService } from './notification.service.js';
+import type { SmsChannelService } from './sms-channel.service.js';
+import type { WebhookChannelService } from './webhook-channel.service.js';
+import { Logger } from '../utils/logger.js';
+
+export type Priority = 'urgent' | 'normal' | 'low';
+
+export interface PriorityNotification {
+  priority: Priority;
+  recipient: string;
+  subject: string;
+  body: string;
+  phoneNumber?: string;
+  webhookEventType?: string;
+  webhookPayload?: Record<string, unknown>;
+}
+
+export class PriorityRouter {
+  private logger = new Logger('PriorityRouter');
+
+  constructor(
+    private smsChannel: SmsChannelService,
+    private emailChannel: NotificationService,
+    private webhookChannel: WebhookChannelService,
+  ) {}
+
+  route(notification: PriorityNotification): void {
+    this.logger.info(
+      `Routing ${notification.priority} notification to ${notification.recipient}`,
+    );
+
+    switch (notification.priority) {
+      case 'urgent':
+        this.smsChannel.sendSms({
+          phoneNumber: notification.phoneNumber ?? notification.recipient,
+          body: `[URGENT] ${notification.subject}: ${notification.body}`,
+        });
+        break;
+
+      case 'normal':
+        this.emailChannel.sendNotification({
+          recipient: notification.recipient,
+          subject: notification.subject,
+          body: notification.body,
+        });
+        break;
+
+      case 'low':
+        this.webhookChannel.deliverToAll(
+          notification.webhookEventType ?? 'notification',
+          notification.webhookPayload ?? {
+            recipient: notification.recipient,
+            subject: notification.subject,
+            body: notification.body,
+          },
+        );
+        break;
+    }
+  }
+}

